260	async function pullPublicContext(userMessage: string): Promise<string> {
261	  const base = buildPublicCorpusContext(userMessage);
262	  const dbUrl = process.env.DATABASE_URL;
263	  if (!dbUrl) return base;
264	  try {
265	    const db = neon(dbUrl);
266	    const keyword = userMessage.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).find(w => w.length > 3);
267	    const pattern = keyword ? `%${keyword}%` : null;
268	    const rows = await db`
269	      SELECT title, content
270	      FROM public_knowledge
271	      WHERE category = 'quote'
272	        AND (${pattern}::text IS NULL OR content ILIKE ${pattern})
273	      ORDER BY importance DESC
274	      LIMIT 6
275	    `;
276	    if (rows.length > 0) {
277	      const quotesBlock = rows.map((r: Row) => `"${r.content}" — RY`).join('\n');
278	      return `${base}\n\n=== RY QUOTES ===\n${quotesBlock}\n=== END RY QUOTES ===`;
279	    }
280	  } catch { /* ignore — fall back to base corpus */ }
281	  return base;
282	}
