287	function scrubPrivateData(text: string): string {
288	  return text
289	    // phone numbers (US and international)
290	    .replace(/\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g, '[REDACTED-PHONE]')
291	    // email addresses
292	    .replace(/\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b/g, '[REDACTED-EMAIL]')
293	    // SSN-shaped patterns
294	    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[REDACTED-ID]')
295	    // legal case numbers (common US formats)
296	    .replace(/\b(case\s*#?\s*\d[\d\-\/]{4,}|\d{2}-[A-Z]{2}-\d{4,})\b/gi, '[REDACTED-CASE]')
297	    // street addresses (number + street keyword)
298	    .replace(/\b\d{1,5}\s+\w+\s+(st|ave|blvd|dr|rd|ln|way|ct|pl|street|avenue|boulevard|drive|road|lane|court|place)\b[^,\n]*/gi, '[REDACTED-ADDRESS]');
