            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex gap-1 px-6 pt-4">
          {(['voice', 'display'] as Tab[]).map(t => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`px-4 py-1.5 rounded-lg text-sm font-medium capitalize transition-colors ${
                tab === t
                  ? 'bg-violet-800/50 text-violet-100'
                  : 'text-violet-500 hover:text-violet-300 hover:bg-violet-900/30'
              }`}
            >
              {t}
            </button>
          ))}
        </div>

        {/* Tab content */}
        <div className="px-6 py-5 min-h-48">
          {tab === 'voice' && (
            <div className="space-y-5">
              <div>
                <label className="text-xs text-violet-500 font-medium block mb-2">Voice Mode</label>
                <p className="text-sm text-violet-300">
                  Current: <span className="font-mono text-violet-200">{voiceSettings.mode}</span>
                </p>
              </div>
              <div>
                <label className="text-xs text-violet-500 font-medium block mb-2">TTS Endpoint</label>
                <input
                  type="text"
                  defaultValue="/api/tts"
                  onBlur={e => onUpdateVoice({ ttsUrl: e.target.value })}
                  className="w-full bg-black/50 border border-violet-800/40 rounded-lg px-3 py-2 text-sm text-violet-200 outline-none focus:border-violet-600/60 transition-colors font-mono"
                />
              </div>
              <div>
                <label className="text-xs text-violet-500 font-medium block mb-2">Follow-up window (ms)</label>
                <input
                  type="number"
                  defaultValue={25000}
                  onBlur={e => onUpdateVoice({ followUpWindowMs: Number(e.target.value) })}
                  className="w-full bg-black/50 border border-violet-800/40 rounded-lg px-3 py-2 text-sm text-violet-200 outline-none focus:border-violet-600/60 transition-colors font-mono"
                />
              </div>
            </div>
          )}

          {tab === 'display' && (
            <div className="space-y-4">
              <p className="text-sm text-violet-400">Display settings coming soon.</p>
              <div className="p-3 rounded-lg bg-violet-950/40 border border-violet-900/30">
                <p className="text-xs text-violet-600 font-mono">Theme: cosmic dark · Font: Space Grotesk + Orbitron</p>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex justify-end px-6 pb-5">
          <button
            onClick={onClose}
            className="px-5 py-2 rounded-xl bg-violet-800/40 hover:bg-violet-700/50 border border-violet-700/40 text-violet-200 text-sm font-medium transition-colors"
          >
            Done
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

interface ActionSheetProps {
  isOpen: boolean;
  onClose: () => void;
  onNewConversation: () => void;
  onAttachNote: () => void;
}

const actions = [
  {
    id: 'new',
    icon: (
      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
      </svg>
    ),
    label: 'New Conversation',
    desc: 'Start a fresh chat',
  },
  {
    id: 'note',
    icon: (
      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
      </svg>
    ),
    label: 'Attach Note',
    desc: 'Add text context to the conversation',
  },
];

export function ActionSheet({ isOpen, onClose, onNewConversation, onAttachNote }: ActionSheetProps) {
  if (!isOpen) return null;

  const handlers: Record<string, () => void> = {
    new: () => { onNewConversation(); onClose(); },
    note: () => { onAttachNote(); onClose(); },
  };

  return (
    <>
      <div className="fixed inset-0 bg-black/50 z-40" onClick={onClose} />
      <div
        className="fixed bottom-0 left-0 right-0 z-50 bg-black/90 border-t border-violet-900/40 backdrop-blur-md rounded-t-2xl pb-safe"
        style={{ animation: 'fade-up 0.25s ease' }}
      >
        <div className="w-12 h-1 bg-violet-800/60 rounded-full mx-auto mt-3 mb-4" />
        <div className="px-4 pb-6 space-y-2">
          {actions.map(a => (
            <button
              key={a.id}
              onClick={handlers[a.id]}
              className="w-full flex items-center gap-4 px-4 py-3.5 rounded-xl bg-violet-950/50 hover:bg-violet-900/50 border border-violet-900/30 hover:border-violet-700/40 transition-all text-left"
            >
              <span className="text-violet-400">{a.icon}</span>
              <div>
                <p className="text-sm font-medium text-violet-100">{a.label}</p>
                <p className="text-xs text-violet-500">{a.desc}</p>
              </div>
            </button>
          ))}
          <button
            onClick={onClose}
            className="w-full py-3 rounded-xl text-violet-500 hover:text-violet-300 text-sm font-medium transition-colors"
          >
            Cancel
          </button>
        </div>
      </div>
    </>
  );
}

'use client';

import { useState, useCallback } from 'react';
import { useOmegaChat } from '@/hooks/use-omega-chat';
import { useVoice } from '@/hooks/use-voice';
import { OmegaHeader } from '@/components/omega/OmegaHeader';
import { ChatView } from '@/components/omega/ChatView';
import { ChatComposer } from '@/components/omega/ChatComposer';
import { ConversationSidebar } from '@/components/omega/ConversationSidebar';
import { TelemetryPanel } from '@/components/omega/TelemetryPanel';
import { VoiceMode } from '@/components/omega/VoiceMode';
import { SystemStateDrawer } from '@/components/omega/SystemStateDrawer';
import { SettingsModal } from '@/components/omega/SettingsModal';
import { ActionSheet } from '@/components/omega/ActionSheet';
import { useIsMobile } from '@/hooks/use-mobile';

const Index = () => {
  const chat = useOmegaChat();
  const isMobile = useIsMobile();

  const [leftOpen, setLeftOpen] = useState(false);
  const [rightOpen, setRightOpen] = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [systemStateOpen, setSystemStateOpen] = useState(false);
  const [actionSheetOpen, setActionSheetOpen] = useState(false);

  const handleVoiceTranscript = useCallback((text: string) => {
    chat.sendMessage(text);
  }, [chat.sendMessage]);

  const voice = useVoice(handleVoiceTranscript);

  const handleAttachNote = useCallback(() => {
    const note = prompt('Enter a text note to attach as context:');
    if (note?.trim()) {
      chat.sendMessage(`[Note attached]: ${note.trim()}`);
    }
  }, [chat.sendMessage]);

  return (
    <div className="h-screen flex omega-cosmic-bg overflow-hidden">
      {!isMobile && (
        <ConversationSidebar
          conversations={chat.conversations}
          activeId={chat.activeConvoId}
          onSelect={chat.switchConversation}
          onNew={chat.newConversation}
          onDelete={chat.deleteConversation}
          isOpen={leftOpen}
          onClose={() => setLeftOpen(false)}
        />
      )}
      {isMobile && (
        <ConversationSidebar
          conversations={chat.conversations}
          activeId={chat.activeConvoId}
          onSelect={chat.switchConversation}
          onNew={chat.newConversation}
          onDelete={chat.deleteConversation}
          isOpen={leftOpen}
          onClose={() => setLeftOpen(false)}
        />
      )}

      <div className="flex-1 flex flex-col min-w-0 relative z-10">
        <OmegaHeader
          systemState={chat.systemState}
          onOpenSettings={() => setSettingsOpen(true)}
          onOpenSystemState={() => setSystemStateOpen(true)}
          onToggleLeftPanel={() => setLeftOpen(!leftOpen)}
          onToggleRightPanel={() => setRightOpen(!rightOpen)}
          showPanelToggles
        />

        <ChatView
          messages={chat.activeConvo?.messages || []}
          onRetry={chat.retryMessage}
          voiceSupported={voice.isSupported}
          onEnterVoice={voice.enterVoiceMode}
        />

        <ChatComposer
          onSend={chat.sendMessage}
          onPlusClick={() => setActionSheetOpen(true)}
          onMicClick={() => {
            if (voice.voiceState.mode === 'listening') voice.stopListening();
            else voice.startListening();
          }}
          disabled={chat.isStreaming}
          isListening={voice.voiceState.mode === 'listening'}
        />
      </div>

      {!isMobile && (
        <TelemetryPanel
          entries={chat.telemetry}
          isOpen={rightOpen}
          onClose={() => setRightOpen(false)}
        />
      )}
      {isMobile && (
        <TelemetryPanel
          entries={chat.telemetry}
          isOpen={rightOpen}
          onClose={() => setRightOpen(false)}
        />
      )}

      <VoiceMode
        voiceState={voice.voiceState}
        onStartListening={voice.startListening}
        onStopListening={voice.stopListening}
        onExit={voice.exitVoiceMode}
        onInterrupt={voice.interruptSpeech}
      />

      <SystemStateDrawer
        state={chat.systemState}
        isOpen={systemStateOpen}
        onClose={() => setSystemStateOpen(false)}
      />

      <SettingsModal
        isOpen={settingsOpen}
        onClose={() => setSettingsOpen(false)}
        voiceSettings={voice.voiceState}
        onUpdateVoice={voice.updateSettings}
      />

      <ActionSheet
        isOpen={actionSheetOpen}
        onClose={() => setActionSheetOpen(false)}
        onNewConversation={chat.newConversation}
        onAttachNote={handleAttachNote}
      />
    </div>
  );
};

export default Index;

